import { createOptions, Options } from '../../src/options'
import { MAP_ERROR, StarlingError } from '../../src/error'

describe('单元测试 - options', () => {
  test('options - 失败 - namespace 不能为空', () => {
    const { ERROR_CODE, ERROR_MESSAGE } = MAP_ERROR.PARAMS_ERROR
    expect(() =>
      createOptions({
        api_key: 'test',
        namespace: '',
        store: {},
        request: {},
        zoneHost: 'https://starling.snssdk.com'
      } as Options)
    ).toThrowError(new StarlingError(ERROR_CODE, ERROR_MESSAGE))
  })

  test('options - 失败 - api_key 不能为空', () => {
    const { ERROR_CODE, ERROR_MESSAGE } = MAP_ERROR.PARAMS_ERROR
    expect(() =>
      createOptions({
        api_key: '',
        namespace: 'test',
        store: {},
        request: {},
        zoneHost: 'https://starling.snssdk.com'
      } as Options)
    ).toThrowError(new StarlingError(ERROR_CODE, ERROR_MESSAGE))
  })

  test('options - 失败 - zoneHost 不能为空', () => {
    const { ERROR_CODE, ERROR_MESSAGE } = MAP_ERROR.PARAMS_ERROR
    expect(() =>
      createOptions({
        api_key: 'test',
        namespace: 'test',
        zoneHost: '',
        store: {},
        request: {}
      } as Options)
    ).toThrowError(new StarlingError(ERROR_CODE, ERROR_MESSAGE))
  })

  test('options - 失败 - store 不能为空', () => {
    const { ERROR_CODE, ERROR_MESSAGE } = MAP_ERROR.PARAMS_ERROR_2
    expect(() =>
      createOptions({
        api_key: 'test',
        namespace: 'test',
        zoneHost: 'host',
        request: {},
        test: true
      } as Options)
    ).toThrowError(new StarlingError(ERROR_CODE, ERROR_MESSAGE))
  })

  test('options - 失败 - request 不能为空', () => {
    const { ERROR_CODE, ERROR_MESSAGE } = MAP_ERROR.PARAMS_ERROR_2
    expect(() =>
      createOptions({
        api_key: 'test',
        namespace: 'test',
        zoneHost: 'host',
        store: {}
      } as Options)
    ).toThrowError(new StarlingError(ERROR_CODE, ERROR_MESSAGE))
  })

  test('options - 创建成功', () => {
    const options = createOptions({
      api_key: 'test',
      namespace: 'test',
      zoneHost: 'host',
      store: {},
      request: {}
    } as Options)
    expect(options).not.toBeNull()
  })
})
